def _app_workflow_run_to_nested(
    app_workflow_run: AppWorkflowRun,
) -> AppWorkflowRunNested:
    """Convert flat AppWorkflowRun to nested format."""
    attrs = AppWorkflowRunAttributes()
    _populate_app_workflow_run_attrs(attrs, app_workflow_run)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        app_workflow_run,
        _APP_WORKFLOW_RUN_REL_FIELDS,
        AppWorkflowRunRelationshipAttributes,
    )
    return AppWorkflowRunNested(
        guid=app_workflow_run.guid,
        type_name=app_workflow_run.type_name,
        status=app_workflow_run.status,
        version=app_workflow_run.version,
        create_time=app_workflow_run.create_time,
        update_time=app_workflow_run.update_time,
        created_by=app_workflow_run.created_by,
        updated_by=app_workflow_run.updated_by,
        classifications=app_workflow_run.classifications,
        classification_names=app_workflow_run.classification_names,
        meanings=app_workflow_run.meanings,
        labels=app_workflow_run.labels,
        business_attributes=app_workflow_run.business_attributes,
        custom_attributes=app_workflow_run.custom_attributes,
        pending_tasks=app_workflow_run.pending_tasks,
        proxy=app_workflow_run.proxy,
        is_incomplete=app_workflow_run.is_incomplete,
        provenance_type=app_workflow_run.provenance_type,
        home_id=app_workflow_run.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _app_workflow_run_from_nested(nested: AppWorkflowRunNested) -> AppWorkflowRun:
    """Convert nested format to flat AppWorkflowRun."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else AppWorkflowRunAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _APP_WORKFLOW_RUN_REL_FIELDS,
        AppWorkflowRunRelationshipAttributes,
    )
    return AppWorkflowRun(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_app_workflow_run_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _app_workflow_run_to_nested_bytes(
    app_workflow_run: AppWorkflowRun, serde: Serde
) -> bytes:
    """Convert flat AppWorkflowRun to nested JSON bytes."""
    return serde.encode(_app_workflow_run_to_nested(app_workflow_run))


def _app_workflow_run_from_nested_bytes(data: bytes, serde: Serde) -> AppWorkflowRun:
    """Convert nested JSON bytes to flat AppWorkflowRun."""
    nested = serde.decode(data, AppWorkflowRunNested)
    return _app_workflow_run_from_nested(nested)


